    /// CheckFPAdvSIMDEnabled64();
    /// bits(datasize) operand1;
    /// bits(datasize) operand2;
    /// bits(datasize) operand3;
    /// bits(datasize) operand4 = V[n];
    ///
    /// case op of
    ///     when VBitOp_VEOR
    ///         operand1 = V[m];
    ///         operand2 = Zeros();
    ///         operand3 = Ones();
    ///     when VBitOp_VBSL
    ///         operand1 = V[m];
    ///         operand2 = operand1;
    ///         operand3 = V[d];
    ///     when VBitOp_VBIT
    ///         operand1 = V[d];
    ///         operand2 = operand1;
    ///         operand3 = V[m];
    ///     when VBitOp_VBIF
    ///         operand1 = V[d];
    ///         operand2 = operand1;
