    /// if !pac && op4 != '00000' then
    ///     UNDEFINED;
    /// elsif pac && (!HavePACExt() || op4 != '11111') then
    ///     UNDEFINED;
    ///
    /// if Rn != '11111' then 
    ///     UNDEFINED;
    /// ```
    ///
