    /// AArch64.CheckForERetTrap(pac, use_key_a);
    /// bits(64) target = ELR[];
    /// boolean auth_then_branch = TRUE;
    ///
    /// if pac then
    ///     if use_key_a then
    ///         target = AuthIA(ELR[], SP[], auth_then_branch);
    ///     else
    ///         target = AuthIB(ELR[], SP[], auth_then_branch);
    ///
    /// AArch64.ExceptionReturn(target, SPSR[]);
    /// ```
