    ///
    ///     when SystemHintOp_TSB
    ///         TraceSynchronizationBarrier();
    ///
    ///     when SystemHintOp_CSDB
    ///         ConsumptionOfSpeculativeDataBarrier();
    ///
    ///     when SystemHintOp_BTI
    ///         SetBTypeNext('00');
    ///
    ///     otherwise // do nothing
    /// ```
