    /// boolean abs = TRUE;
    ///
    /// // Scalar single-precision and double-precision
    /// integer d = UInt(Rd);
    /// integer n = UInt(Rn);
    /// integer m = UInt(Rm);
    /// integer esize = 32 << UInt(sz);
    /// integer datasize = esize;
