    /// integer n = UInt(Rn);
    /// integer m = UInt(Rm);
    /// if sz:Q == '10' then UNDEFINED;
    /// integer esize = 32 << UInt(sz);
    /// integer datasize = if Q == '1' then 128 else 64;
