    /// bits(datasize) operand3 = V[d];
    /// bits(datasize) result;
    /// bits(esize DIV 2) element1;
    /// bits(esize DIV 2) element2 = Elem[operand2, index, esize DIV 2];
    ///
    /// for e = 0 to elements-1
