    ///             when Constraint_UNDEF      UNDEFINED;
    ///             when Constraint_NOP        EndOfInstruction();
    ///     if s == n && n != 31 then
    ///         Constraint c = ConstrainUnpredictable(Unpredictable_BASEOVERLAP);
