    ///
    /// ```
    /// if !HaveSVE() then UNDEFINED;
    /// integer esize = 8 << UInt(size);
    /// integer g = UInt(Pg);
    /// integer dn = UInt(Zdn);
    /// integer m = UInt(Zm);
