    /// ```
    /// CheckSVEEnabled();
    /// integer elements = VL DIV esize;
    /// bits(PL) mask = P[g];
    /// bits(VL) operand1 = Z[dn];
    /// bits(VL) operand2 = Z[m];
    /// bits(VL) result;
