    ///             data = bits(datasize) UNKNOWN;
    ///         else
    ///             data = X[t];
    ///         Mem[address, datasize DIV 8, acctype] = data;
    ///
    ///     when MemOp_LOAD
    ///         data = Mem[address, datasize DIV 8, acctype];
    ///         if signed then
