    /// //    32+B = 1, 32+H = 2, 32+S = X, 32+D = X
    /// //    16+B = 2, 16+H = X, 16+S = X, 16+D = X
    /// //     8+B = X,  8+H = X,  8+S = X,  8+D = X
    /// // => 3-(op+size) (index bits in group)
