    /// integer datasize = esize;
    /// integer elements = 1;
    /// boolean unsigned = (U == '1');
    ///
    /// // Vector
    /// integer d = UInt(Rd);
    /// integer n = UInt(Rn);
    /// integer m = UInt(Rm);
