    /// ```
    /// CheckFPAdvSIMDEnabled64();
    /// bits(datasize) operand  = V[n];
    /// bits(datasize) operand2 = V[d];
    /// bits(datasize) result;
    /// bits(esize) mask = LSR(Ones(esize), shift);
    /// bits(esize) shifted;
    ///
    /// for e = 0 to elements-1
