    ///     vect_offset = 0x14;
    ///
    ///     AArch32.EnterHypMode(exception, preferred_exception_return, vect_offset);// AArch32.TakeMonitorTrapException()
    /// // ==================================
    /// // Exceptions routed to Monitor mode as a Monitor Trap exception.
