    ///                                      extflag, debugmoe, errortype, secondstage, s2fs1walk);// AArch32.DomainFault()
    /// // =====================
    ///
    /// FaultRecord AArch32.DomainFault(bits(4) domain, integer level, AccType acctype, boolean iswrite)
