    ///
    ///     // Check this Translation Table Base Register is not disabled.
    ///     if disabled then
    ///         level = 1;
    ///         result.addrdesc.fault = AArch32.TranslationFault(ipaddress, domain, level, acctype, iswrite,
    ///                                                          secondstage, s2fs1walk);
    ///         return result;
    ///
