    ///
    ///     vaddress = bits(64) UNKNOWN;
    ///     exception = AArch64.AbortSyndrome(Exception_VectorCatch, fault, vaddress);
    ///
    ///     AArch64.TakeException(EL2, exception, preferred_exception_return, vect_offset);// AArch64.WatchpointException()
    /// // =============================
