    ///     bits(128) APIBKey_EL1;
    ///
    ///     APIBKey_EL1 = APIBKeyHi_EL1<63:0> : APIBKeyLo_EL1<63:0>;
    ///     case PSTATE.EL of
    ///         when EL0
