    ///             TrapEL3 = HaveEL(EL3) && SCR_EL3.API == '0';
    ///         when EL1
    ///             Enable = SCTLR_EL1.EnIB;
    ///             TrapEL2 = EL2Enabled() && HCR_EL2.API == '0';
    ///             TrapEL3 = HaveEL(EL3) && SCR_EL3.API == '0';
    ///         when EL2
    ///             Enable = SCTLR_EL2.EnIB;
    ///             TrapEL2 = FALSE;
    ///             TrapEL3 = HaveEL(EL3) && SCR_EL3.API == '0';
    ///         when EL3
    ///             Enable = SCTLR_EL3.EnIB;
    ///             TrapEL2 = FALSE;
    ///             TrapEL3 = FALSE;
