    ///             // Produce zero if value is zero or flush-to-zero is selected
    ///             if IsZero(frac16) || fpcr.FZ16 == '1' then
    ///                 fptype = FPType_Zero;  value = 0.0;
    ///             else
    ///                 fptype = FPType_Nonzero;  value = 2.0^-14 * (Real(UInt(frac16)) * 2.0^-10);
