    /// ```
    /// integer d = UInt(Rd);
    /// integer n = UInt(Rn);
    /// integer m = UInt(Rm);
    ///
    /// integer datasize = if Q == '1' then 128 else 64;
    /// integer elements = datasize DIV 8;
    /// integer regs = UInt(len) + 1;
    /// boolean is_tbl = (op == '0');
    /// ```
    ///
    /// ## Operation
    ///
    /// ```
